#include <stdio.h>
#include <stdlib.h>

// Node structure
typedef struct Node {
 char* name;
 int heuristic;
 struct Node** successors;
 int* costs;
 int num_successors;
 int cost;
 int solved;
} Node;

// Function to create a new node
Node* create_node(char* name, int heuristic) {
 Node* node = malloc(sizeof(Node));
 node->name = name;
 node->heuristic = heuristic;
 node->successors = NULL;
 node->costs = NULL;
 node->num_successors = 0;
 node->cost = 0;
 node->solved = 0;
 return node;
}

// Function to add a successor to a node
void add_successor(Node* node, Node* successor, int cost) {
 node->num_successors++;
 node->successors = realloc(node->successors, node->num_successors * sizeof(Node*));
 node->successors[node->num_successors - 1] = successor;
 node->costs = realloc(node->costs, node->num_successors * sizeof(int));
 node->costs[node->num_successors - 1] = cost;
}

// Function to update the cost of a node
void update_cost(Node* node) {
 if (node->solved) return;
 if (node->num_successors == 0) {
 node->cost = node->heuristic;
 } else if (node->name[0] == 'A') { // AND node
 int sum = 0;
 for (int i = 0; i < node->num_successors; i++) {
 sum += node->costs[i] + node->successors[i]->cost;
 }
 node->cost = sum;
 } else if (node->name[0] == 'O') { // OR node
 int min = node->costs[0] + node->successors[0]->cost;
 for (int i = 1; i < node->num_successors; i++) {
 if (node->costs[i] + node->successors[i]->cost < min) {
 min = node->costs[i] + node->successors[i]->cost;
 }
 }
 node->cost = min;
 }
}

// Function to mark a node as solved
void mark_solved(Node* node) {
 node->solved = 1;
}

int main() {
 // Create nodes and add successors
 Node* start_node = create_node("Start", 5);
 Node* node1 = create_node("Node 1", 3);
 Node* node2 = create_node("Node 2", 2);
 add_successor(start_node, node1, 1);
 add_successor(start_node, node2, 2);

 // Update costs and mark solved
 update_cost(start_node);
 mark_solved(node1);
 update_cost(start_node);

 return 0;
}
